"use strict";parserFactory.register("fullnovel.co",()=>new FullnovelParser);class FullnovelParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("ul.chapter-list");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector(".chapter-content")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"main")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.text-xs")]}}